    KERNEL_STACK_SIZE, PAGE_SIZE, TRAMPOLINE, USER_HEAP_BOTTOM, USER_HEAP_SIZE, USER_STACK_SIZE,
    USER_STACK_TOP, USER_TRAP_CONTEXT_TOP,
};
