#[cfg(target_arch = "riscv64")]
pub struct KernelStack(pub usize);

#[cfg(target_arch = "loongarch64")]
pub struct KernelStack(Vec<u8>);

/// Allocate a kernel stack for a task
#[cfg(target_arch = "riscv64")]
pub fn kstack_alloc() -> KernelStack {
    //debug!("in kstack alloc");
    let kstack_id = KSTACK_ALLOCATOR.exclusive_access().alloc();
    //debug!("kstack id is : {}", kstack_id);
    let (kstack_bottom, kstack_top) = kernel_stack_position(kstack_id);
    debug!("to map kernel space");
    debug!(
        "bottom is : {:#x}, top is : {:#x}",
        kstack_bottom, kstack_top
    );
    KERNEL_SPACE.exclusive_access().insert_framed_area(
        kstack_bottom.into(),
        kstack_top.into(),
        MapPermission::R | MapPermission::W,
        MapAreaType::Stack,
    );
    KernelStack(kstack_id)
}

#[cfg(target_arch = "loongarch64")]
pub fn kstack_alloc() -> KernelStack {
    KernelStack(alloc::vec![0u8; KERNEL_STACK_SIZE])
}

#[cfg(target_arch = "riscv64")]
impl Drop for KernelStack {
    fn drop(&mut self) {
        debug!("to drop kernel stack");
        let (kernel_stack_bottom, ktop) = kernel_stack_position(self.0);
        debug!(
            "kbottom is : {:#x}, ktop is : {:#x}",
            kernel_stack_bottom, ktop
        );
        let kernel_stack_bottom_va: VirtAddr = kernel_stack_bottom.into();
        KERNEL_SPACE
            .exclusive_access()
            .remove_area_with_start_vpn(kernel_stack_bottom_va.floor());
        debug!("remove ok");
        KSTACK_ALLOCATOR.exclusive_access().dealloc(self.0);
        debug!("drop kernel stack ok");
    }
}

/// Create a kernelstack
impl KernelStack {
    /// return the top of the kernel stack
    pub fn get_top(&self) -> usize {
        debug!("in kernel stack, to get top");
        #[cfg(target_arch = "riscv64")]
        let (_, kernel_stack_top) = kernel_stack_position(self.0);
        #[cfg(target_arch = "loongarch64")]
        let (_, kernel_stack_top) = kernel_stack_position(&self.0);
        kernel_stack_top
    }
    /// Push a variable of type T into the top of the KernelStack and return its raw pointer
    pub fn push_on_top<T>(&self, value: T) -> *mut T
    where
        T: Sized,
    {
        let kernel_stack_top = self.get_top();
        let ptr_mut = (kernel_stack_top - core::mem::size_of::<T>()) as *mut T;
        unsafe {
            *ptr_mut = value;
        }
        ptr_mut
    }
}

/// Return the bottom addr (low addr) of the trap context for a task
pub fn trap_cx_bottom_from_tid(tid: usize) -> usize {
    //debug!("in trap cx bottom from tid, the tid is : {}", tid);
    USER_TRAP_CONTEXT_TOP - tid * PAGE_SIZE
}
/// Return the bottom addr (high addr) of the user stack for a task
pub fn ustack_bottom_from_tid(tid: usize) -> usize {
    USER_STACK_TOP - tid * (PAGE_SIZE + USER_STACK_SIZE)
}

pub fn heap_bottom_from_id(id: usize) -> usize {
    USER_HEAP_BOTTOM + id * (USER_HEAP_SIZE + PAGE_SIZE)
}

use std::{env, io::Result};

fn main() -> Result<()> {
    gen_linker_script()
}

fn gen_linker_script() -> Result<()> {
    let target_arch = env::var("CARGO_CFG_TARGET_ARCH").expect("can't find target");
    let fname = format!("linker_{}.lds", target_arch);
    let (output_arch, kernel_base) = if target_arch.contains("riscv64") {
        ("riscv", "0x80200000") // OpenSBI
    } else if target_arch.contains("loongarch64") {
        ("loongarch64", "0x82000000")
    } else {
        (target_arch.as_str(), "0")
    };
    let ld_content = std::fs::read_to_string("linker.lds")?;
    let ld_content = ld_content.replace("%ARCH%", output_arch);
    let ld_content = ld_content.replace("%KERNEL_BASE%", kernel_base);

    std::fs::write(&fname, ld_content)?;
    println!("cargo:rustc-link-arg=-T{}", fname);
    println!("cargo:rerun-if-env-changed=CARGO_CFG_KERNEL_BASE");
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-changed=linker.lds");
    Ok(())
}
